CREATE TABLE IF NOT EXISTS merit_lists (id VARCHAR(36) PRIMARY KEY, college_id VARCHAR(64) NOT NULL, exam_id VARCHAR(36) NOT NULL REFERENCES exams(id) ON DELETE CASCADE, scope_type VARCHAR(32) NOT NULL, scope_id VARCHAR(64) NOT NULL DEFAULT '', basis VARCHAR(32) NOT NULL, status VARCHAR(32) NOT NULL DEFAULT 'DRAFT', title VARCHAR(180) NOT NULL, tie_breakers TEXT NOT NULL, analytics_json TEXT NOT NULL DEFAULT '{}', generated_by VARCHAR(64) NOT NULL, published_by VARCHAR(64), generated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP, published_at TIMESTAMP WITH TIME ZONE, CONSTRAINT uq_merit_list_scope_basis UNIQUE (college_id, exam_id, scope_type, scope_id, basis));
CREATE INDEX IF NOT EXISTS ix_merit_lists_college_exam_status ON merit_lists (college_id, exam_id, status);
CREATE INDEX IF NOT EXISTS ix_merit_lists_college_scope ON merit_lists (college_id, scope_type, scope_id);
CREATE TABLE IF NOT EXISTS merit_list_items (id VARCHAR(36) PRIMARY KEY, college_id VARCHAR(64) NOT NULL, merit_list_id VARCHAR(36) NOT NULL REFERENCES merit_lists(id) ON DELETE CASCADE, result_id VARCHAR(36) NOT NULL REFERENCES student_results(id) ON DELETE CASCADE, grade_calculation_id VARCHAR(36) REFERENCES student_grade_calculations(id) ON DELETE SET NULL, student_id VARCHAR(36) NOT NULL REFERENCES students(id) ON DELETE CASCADE, rank INTEGER NOT NULL, score NUMERIC(7,3) NOT NULL, percentage NUMERIC(5,2) NOT NULL, gpa NUMERIC(4,2), tie_breaker_value VARCHAR(180), is_certificate_issued BOOLEAN NOT NULL DEFAULT FALSE, CONSTRAINT uq_merit_item_student UNIQUE (merit_list_id, student_id));
CREATE INDEX IF NOT EXISTS ix_merit_items_list_rank ON merit_list_items (merit_list_id, rank);
CREATE TABLE IF NOT EXISTS merit_certificates (id VARCHAR(36) PRIMARY KEY, college_id VARCHAR(64) NOT NULL, merit_item_id VARCHAR(36) NOT NULL REFERENCES merit_list_items(id) ON DELETE CASCADE, verification_code VARCHAR(80) NOT NULL, printable_html TEXT NOT NULL, issued_by VARCHAR(64) NOT NULL, issued_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT uq_merit_certificate_item UNIQUE (college_id, merit_item_id), CONSTRAINT uq_merit_certificate_code UNIQUE (college_id, verification_code));
